type Result struct {
	ErrorMessage string
	Ok           bool
	Value        float64
}

func (v *Result) marshal() []byte {
	if v == nil {
		return nil
	}
	var buf []byte
	buf = pbAppendString(buf, 1, v.ErrorMessage)
	buf = pbAppendBool(buf, 2, v.Ok)
	buf = pbAppendDouble(buf, 3, v.Value)
	return buf
}

func unmarshalResult(data []byte) *Result {
	v := &Result{}
	pr := &pbReader{data: data}
	for f, w, ok := pr.next(); ok; f, w, ok = pr.next() {
		switch f {
		case 1:
			v.ErrorMessage = pr.readString()
		case 2:
			v.Ok = pr.readBool()
		case 3:
			v.Value = pr.readDouble()
		default:
			pr.skip(w)
		}
	}
	return v
}

