func (a *loggerCallbackAdapter) HandleCallback(methodID int32, req []byte) ([]byte, error) {
	switch methodID {
	case 0: // Level
		_v, err := a.impl.Level()
		if err != nil {
			return nil, err
		}
		var _out []byte
		_out = pbAppendInt32(_out, 1, _v)
		return _out, nil
	case 1: // Log
		var message string
		_r := &pbReader{data: req}
		for _f, _w, _ok := _r.next(); _ok; _f, _w, _ok = _r.next() {
			switch _f {
			case 1:
				message = _r.readString()
			default:
				_r.skip(_w)
			}
		}
		err := a.impl.Log(message)
		if err != nil {
			return nil, err
		}
		return nil, nil
	}
	return nil, fmt.Errorf("unknown callback method %d", methodID)
}

